proof fn phi_1_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_2_tla_forall_unfold_intensional_bridge(ex: Execution<int>, a_to_p: spec_fn(int) -> TempPred<int>, a: int)
    requires
        tla_forall(a_to_p).satisfied_by(ex),
    ensures
        a_to_p(a).satisfied_by(ex),
{
    tla_forall_unfold::<int, int>(ex, a_to_p);
}

proof fn phi_3_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_4_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_5_tla_forall_always_equality_bridge(a_to_p: spec_fn(int) -> TempPred<int>)
    ensures
        tla_forall(|a: int| always(a_to_p(a))) == always(tla_forall(a_to_p)),
{
    tla_forall_always_equality::<int, int>(a_to_p);
}
